INSERT INTO `formule_comptabilite` VALUES (1,'Ebe','EBE=Valeur Ajoutee (VA)+Subventions dexploitation−Impots, taxes et versements assimiles−Charges de personnel'),(2,'Valeur Ajoutee ','VA = Chiffre d\'Affaires - Consommations Intermdiaires'),(3,'Cash-flow ','Cash-flow oprationnel = EBE + Dotations aux amortissements et provisions - Variation du BFR'),(4,'Ratio EBE','Ratio EBE = (EBE / Chiffre d\'affaires) * 100'),(5,'Ratio de tresorerie','Ratio de tresorerie = Tresorerie / Dettes  court terme'),(6,'Productionde exercice','Production vendue+Production stockee+Production immobiliseeProduction de l exercice=Production vendue+Production stockee+Production immobilisee'),(7,'Resultat brut  exploitation (RBE)','Resultat Brut d Exploitation=EBE&#8722;Amortissements&#8722;Provisions'),(8,'Ratio de liquidite genrale','Actifs circulants sur Passifs circulants'),(9,'Ratio de solvabilite ','Capitaux propres sur Total du passif'),(10,'Marge Commerciale','=Ventes de marchandises&#8722;Achats de marchandises consommes'),(11,'Resultat Courant Avant Impots','Resultat d exploitation+Produits financiers&#8722;Charges financieres'),(12,'     Resultat net comptable','=Resultat courant avant impots&#8722;Impot sur les benefices&#8722;Elements exceptionnels'),(13,' Fonds de Roulement Net Global','FRNG=Capitaux propres+Dettes financieres&#8722;Actif immobilise'),(14,'     Besoin en Fonds de Roulement','BFR=Creances clients+Stocks&#8722;Dettes fournisseurs'),(15,'   Capacite  autofinancement (CAF)','CAF = Rsultat Net + Charges Non Dcaissees - Produits Non Encaisss'),(16,'Flux de tresorerie ','FTO = Rsultat net + Amortissements + Provisions + Variations du fonds de roulement'),(17,'Taux de marge nette','=Chiffre d affaires sur Resultat net'),(18,' Taux de rentabilite economique','=Resultat d exploitation sur Actifs economiques'),(19,'Taux de rentabilite des capitaux propres','=Resultat net sur Capitaux propres'),(20,'Endettement net','=Dettes financieres&#8722;Tresorerie active'),(21,'Taux de couverture des immobilisations','=Capitaux propres+Dettes a long terme sur Actifs immobilises'),(22,'Coefficient d exploitation','=Charges d exploitation sur Chiffre d affaires'),(23,'Taux d autofinancement','=Capacite d autofinancement sur Investissements realises'),(24,'Valeur future','VF=C0(1+r)n C0 = Capital initial        r = Taux dinteret (par periode)        n = Nombre de periodes'),(25,'Annuite','A=C0r1&#8722;(1+r)&#8722;n'),(26,'Van','VAN = \\sum_{t=0}^{n} \\frac{CF_t}{(1 + r)^t} - I');
/*!40000 ALTER TABLE `formule_comptabilite` ENABLE KEYS */;
